<?php/** * WooCommerce Integration * * @package AquaLuxe * @since 1.0.0 */// Exit if accessed directly.if ( ! defined( 'ABSPATH' ) ) {	exit;}// Return early if WooCommerce is not active.if ( ! class_exists( 'WooCommerce' ) ) {	return;}/** * WooCommerce setup function. * * @return void */function aqualuxe_woocommerce_setup() {	// Add theme support for WooCommerce.	add_theme_support( 'woocommerce' );		// Add support for WooCommerce product gallery features.	add_theme_support( 'wc-product-gallery-zoom' );	add_theme_support( 'wc-product-gallery-lightbox' );	add_theme_support( 'wc-product-gallery-slider' );		// Register WooCommerce specific sidebars.	register_sidebar(		array(			'name'          => esc_html__( 'Shop Sidebar', 'aqualuxe' ),			'id'            => 'shop-sidebar',			'description'   => esc_html__( 'Add widgets here to appear in your shop sidebar.', 'aqualuxe' ),			'before_widget' => '<section id="%1$s" class="widget %2$s">',			'after_widget'  => '</section>',			'before_title'  => '<h2 class="widget-title">',			'after_title'   => '</h2>',		)	);}add_action( 'after_setup_theme', 'aqualuxe_woocommerce_setup' );/** * WooCommerce specific scripts & stylesheets. * * @return void */function aqualuxe_woocommerce_scripts() {	// Enqueue WooCommerce styles.	wp_enqueue_style(		'aqualuxe-woocommerce',		aqualuxe_asset_path( 'css/woocommerce.css' ),		array( 'aqualuxe-styles' ),		AQUALUXE_VERSION	);		// Enqueue WooCommerce scripts.	wp_enqueue_script(		'aqualuxe-woocommerce',		aqualuxe_asset_path( 'js/woocommerce.js' ),		array( 'jquery', 'aqualuxe-scripts' ),		AQUALUXE_VERSION,		true	);		// Add script data.	wp_localize_script(		'aqualuxe-woocommerce',		'aqualuxeWooCommerce',		array(			'ajaxUrl'       => admin_url( 'admin-ajax.php' ),			'nonce'         => wp_create_nonce( 'aqualuxe-woocommerce-nonce' ),			'addToCartText' => esc_html__( 'Add to Cart', 'aqualuxe' ),			'viewCartText'  => esc_html__( 'View Cart', 'aqualuxe' ),			'i18n'          => array(				'quickView'      => esc_html__( 'Quick View', 'aqualuxe' ),				'addToWishlist'  => esc_html__( 'Add to Wishlist', 'aqualuxe' ),				'removeFromWishlist' => esc_html__( 'Remove from Wishlist', 'aqualuxe' ),				'addedToCart'    => esc_html__( 'Added to Cart', 'aqualuxe' ),				'addingToCart'   => esc_html__( 'Adding...', 'aqualuxe' ),				'compare'        => esc_html__( 'Compare', 'aqualuxe' ),				'loadingQuickView' => esc_html__( 'Loading Quick View...', 'aqualuxe' ),				'errorMessage'   => esc_html__( 'Something went wrong. Please try again.', 'aqualuxe' ),			),		)	);}add_action( 'wp_enqueue_scripts', 'aqualuxe_woocommerce_scripts' );/** * Disable the default WooCommerce stylesheet. * * @return void */function aqualuxe_dequeue_woocommerce_styles() {	// Dequeue the default WooCommerce stylesheet.	wp_dequeue_style( 'woocommerce-general' );	wp_dequeue_style( 'woocommerce-layout' );	wp_dequeue_style( 'woocommerce-smallscreen' );}add_action( 'wp_enqueue_scripts', 'aqualuxe_dequeue_woocommerce_styles', 100 );/** * Related Products Args. * * @param array $args Related products args. * @return array Modified related products args. */function aqualuxe_related_products_args( $args ) {	$args['posts_per_page'] = get_theme_mod( 'aqualuxe_related_products', 4 );	$args['columns'] = get_theme_mod( 'aqualuxe_product_columns', 4 );		return $args;}add_filter( 'woocommerce_output_related_products_args', 'aqualuxe_related_products_args' );/** * Product columns wrapper. * * @return void */function aqualuxe_product_columns_wrapper() {	$columns = get_theme_mod( 'aqualuxe_product_columns', 4 );	echo '<div class="columns-' . absint( $columns ) . '">';}add_action( 'woocommerce_before_shop_loop', 'aqualuxe_product_columns_wrapper', 40 );/** * Product columns wrapper close. * * @return void */function aqualuxe_product_columns_wrapper_close() {	echo '</div>';}add_action( 'woocommerce_after_shop_loop', 'aqualuxe_product_columns_wrapper_close', 40 );/** * Set the number of products per page. * * @return int Number of products. */function aqualuxe_products_per_page() {	return get_theme_mod( 'aqualuxe_products_per_page', 12 );}add_filter( 'loop_shop_per_page', 'aqualuxe_products_per_page', 20 );/** * Set the number of product columns. * * @return int Number of columns. */function aqualuxe_loop_columns() {	return get_theme_mod( 'aqualuxe_product_columns', 4 );}add_filter( 'loop_shop_columns', 'aqualuxe_loop_columns' );/** * Add 'woocommerce-active' class to the body tag. * * @param array $classes CSS classes applied to the body tag. * @return array CSS classes with 'woocommerce-active' class added. */function aqualuxe_woocommerce_active_body_class( $classes ) {	$classes[] = 'woocommerce-active';		return $classes;}add_filter( 'body_class', 'aqualuxe_woocommerce_active_body_class' );/** * Remove default WooCommerce wrapper. */remove_action( 'woocommerce_before_main_content', 'woocommerce_output_content_wrapper', 10 );remove_action( 'woocommerce_after_main_content', 'woocommerce_output_content_wrapper_end', 10 );/** * Add custom WooCommerce wrapper. */function aqualuxe_woocommerce_wrapper_before() {	?>	<div id="primary" class="content-area">		<main id="main" class="site-main" role="main">	<?php}add_action( 'woocommerce_before_main_content', 'aqualuxe_woocommerce_wrapper_before' );/** * Add custom WooCommerce wrapper close. */function aqualuxe_woocommerce_wrapper_after() {	?>		</main><!-- #main -->	</div><!-- #primary -->	<?php}add_action( 'woocommerce_after_main_content', 'aqualuxe_woocommerce_wrapper_after' );/** * Add custom WooCommerce sidebar. */function aqualuxe_woocommerce_sidebar() {	if ( is_active_sidebar( 'shop-sidebar' ) ) {		?>		<div id="secondary" class="widget-area shop-sidebar" role="complementary">			<?php dynamic_sidebar( 'shop-sidebar' ); ?>		</div><!-- #secondary -->		<?php	}}remove_action( 'woocommerce_sidebar', 'woocommerce_get_sidebar', 10 );add_action( 'woocommerce_sidebar', 'aqualuxe_woocommerce_sidebar' );/** * Add quick view button to product loop. */function aqualuxe_quick_view_button() {	if ( ! get_theme_mod( 'aqualuxe_show_quick_view', true ) ) {		return;	}		global $product;		echo '<button class="quick-view-button" data-product-id="' . esc_attr( $product->get_id() ) . '">';	echo '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" class="w-6 h-6"><path d="M12 15a3 3 0 100-6 3 3 0 000 6z" /><path fill-rule="evenodd" d="M1.323 11.447C2.811 6.976 7.028 3.75 12.001 3.75c4.97 0 9.185 3.223 10.675 7.69.12.362.12.752 0 1.113-1.487 4.471-5.705 7.697-10.677 7.697-4.97 0-9.186-3.223-10.675-7.69a1.762 1.762 0 010-1.113zM17.25 12a5.25 5.25 0 11-10.5 0 5.25 5.25 0 0110.5 0z" clip-rule="evenodd" /></svg>';	echo '<span class="screen-reader-text">' . esc_html__( 'Quick View', 'aqualuxe' ) . '</span>';	echo '</button>';}add_action( 'woocommerce_after_shop_loop_item', 'aqualuxe_quick_view_button', 15 );/** * Add wishlist button to product loop. */function aqualuxe_wishlist_button() {	if ( ! get_theme_mod( 'aqualuxe_show_wishlist', true ) ) {		return;	}		global $product;		echo '<button class="wishlist-button" data-product-id="' . esc_attr( $product->get_id() ) . '">';	echo '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" class="w-6 h-6"><path d="M11.645 20.91l-.007-.003-.022-.012a15.247 15.247 0 01-.383-.218 25.18 25.18 0 01-4.244-3.17C4.688 15.36 2.25 12.174 2.25 8.25 2.25 5.322 4.714 3 7.688 3A5.5 5.5 0 0112 5.052 5.5 5.5 0 0116.313 3c2.973 0 5.437 2.322 5.437 5.25 0 3.925-2.438 7.111-4.739 9.256a25.175 25.175 0 01-4.244 3.17 15.247 15.247 0 01-.383.219l-.022.012-.007.004-.003.001a.752.752 0 01-.704 0l-.003-.001z" /></svg>';	echo '<span class="screen-reader-text">' . esc_html__( 'Add to Wishlist', 'aqualuxe' ) . '</span>';	echo '</button>';}add_action( 'woocommerce_after_shop_loop_item', 'aqualuxe_wishlist_button', 20 );/** * Add compare button to product loop. */function aqualuxe_compare_button() {	global $product;		echo '<button class="compare-button" data-product-id="' . esc_attr( $product->get_id() ) . '">';	echo '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" class="w-6 h-6"><path d="M18.375 2.25c-1.035 0-1.875.84-1.875 1.875v15.75c0 1.035.84 1.875 1.875 1.875h.75c1.035 0 1.875-.84 1.875-1.875V4.125c0-1.036-.84-1.875-1.875-1.875h-.75zM9.75 8.625c0-1.036.84-1.875 1.875-1.875h.75c1.036 0 1.875.84 1.875 1.875v11.25c0 1.035-.84 1.875-1.875 1.875h-.75a1.875 1.875 0 01-1.875-1.875V8.625zM3 13.125c0-1.036.84-1.875 1.875-1.875h.75c1.036 0 1.875.84 1.875 1.875v6.75c0 1.035-.84 1.875-1.875 1.875h-.75A1.875 1.875 0 013 19.875v-6.75z" /></svg>';	echo '<span class="screen-reader-text">' . esc_html__( 'Compare', 'aqualuxe' ) . '</span>';	echo '</button>';}add_action( 'woocommerce_after_shop_loop_item', 'aqualuxe_compare_button', 25 );/** * Add product badge to product loop. */function aqualuxe_product_badge() {	global $product;		if ( $product->is_on_sale() ) {		echo '<span class="product-badge sale">' . esc_html__( 'Sale', 'aqualuxe' ) . '</span>';	} elseif ( ! $product->is_in_stock() ) {		echo '<span class="product-badge out-of-stock">' . esc_html__( 'Out of Stock', 'aqualuxe' ) . '</span>';	} elseif ( $product->is_featured() ) {		echo '<span class="product-badge featured">' . esc_html__( 'Featured', 'aqualuxe' ) . '</span>';	} elseif ( $product->get_date_created() && ( time() - $product->get_date_created()->getTimestamp() ) < 7 * DAY_IN_SECONDS ) {		echo '<span class="product-badge new">' . esc_html__( 'New', 'aqualuxe' ) . '</span>';	}}add_action( 'woocommerce_before_shop_loop_item_title', 'aqualuxe_product_badge', 10 );/** * Add product sharing to single product. */function aqualuxe_product_sharing() {	if ( ! is_singular( 'product' ) ) {		return;	}		echo '<div class="product-sharing">';	echo '<h3 class="sharing-title">' . esc_html__( 'Share This Product', 'aqualuxe' ) . '</h3>';	echo '<div class="sharing-links">';		$product_url = urlencode( get_permalink() );	$product_title = urlencode( get_the_title() );		// Facebook	echo '<a href="https://www.facebook.com/sharer/sharer.php?u=' . esc_attr( $product_url ) . '" class="sharing-link facebook" target="_blank" rel="noopener noreferrer">';	echo '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 320 512" fill="currentColor"><path d="M279.14 288l14.22-92.66h-88.91v-60.13c0-25.35 12.42-50.06 52.24-50.06h40.42V6.26S260.43 0 225.36 0c-73.22 0-121.08 44.38-121.08 124.72v70.62H22.89V288h81.39v224h100.17V288z"/></svg>';	echo '<span class="screen-reader-text">' . esc_html__( 'Share on Facebook', 'aqualuxe' ) . '</span>';	echo '</a>';		// Twitter	echo '<a href="https://twitter.com/intent/tweet?url=' . esc_attr( $product_url ) . '&text=' . esc_attr( $product_title ) . '" class="sharing-link twitter" target="_blank" rel="noopener noreferrer">';	echo '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" fill="currentColor"><path d="M459.37 151.716c.325 4.548.325 9.097.325 13.645 0 138.72-105.583 298.558-298.558 298.558-59.452 0-114.68-17.219-161.137-47.106 8.447.974 16.568 1.299 25.34 1.299 49.055 0 94.213-16.568 130.274-44.832-46.132-.975-84.792-31.188-98.112-72.772 6.498.974 12.995 1.624 19.818 1.624 9.421 0 18.843-1.3 27.614-3.573-48.081-9.747-84.143-51.98-84.143-102.985v-1.299c13.969 7.797 30.214 12.67 47.431 13.319-28.264-18.843-46.781-51.005-46.781-87.391 0-19.492 5.197-37.36 14.294-52.954 51.655 63.675 129.3 105.258 216.365 109.807-1.624-7.797-2.599-15.918-2.599-24.04 0-57.828 46.782-104.934 104.934-104.934 30.213 0 57.502 12.67 76.67 33.137 23.715-4.548 46.456-13.32 66.599-25.34-7.798 24.366-24.366 44.833-46.132 57.827 21.117-2.273 41.584-8.122 60.426-16.243-14.292 20.791-32.161 39.308-52.628 54.253z"/></svg>';	echo '<span class="screen-reader-text">' . esc_html__( 'Share on Twitter', 'aqualuxe' ) . '</span>';	echo '</a>';		// Pinterest	$product_image = wp_get_attachment_image_src( get_post_thumbnail_id(), 'full' );	$product_image_url = $product_image ? urlencode( $product_image[0] ) : '';		echo '<a href="https://pinterest.com/pin/create/button/?url=' . esc_attr( $product_url ) . '&media=' . esc_attr( $product_image_url ) . '&description=' . esc_attr( $product_title ) . '" class="sharing-link pinterest" target="_blank" rel="noopener noreferrer">';	echo '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 384 512" fill="currentColor"><path d="M204 6.5C101.4 6.5 0 74.9 0 185.6 0 256 39.6 296 63.6 296c9.9 0 15.6-27.6 15.6-35.4 0-9.3-23.7-29.1-23.7-67.8 0-80.4 61.2-137.4 140.4-137.4 68.1 0 118.5 38.7 118.5 109.8 0 53.1-21.3 152.7-90.3 152.7-24.9 0-46.2-18-46.2-43.8 0-37.8 26.4-74.4 26.4-113.4 0-66.2-93.9-54.2-93.9 25.8 0 16.8 2.1 35.4 9.6 50.7-13.8 59.4-42 147.9-42 209.1 0 18.9 2.7 37.5 4.5 56.4 3.4 3.8 1.7 3.4 6.9 1.5 50.4-69 48.6-82.5 71.4-172.8 12.3 23.4 44.1 36 69.3 36 106.2 0 153.9-103.5 153.9-196.8C384 71.3 298.2 6.5 204 6.5z"/></svg>';	echo '<span class="screen-reader-text">' . esc_html__( 'Share on Pinterest', 'aqualuxe' ) . '</span>';	echo '</a>';		// Email	echo '<a href="mailto:?subject=' . esc_attr( $product_title ) . '&body=' . esc_attr( $product_url ) . '" class="sharing-link email">';	echo '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" class="w-6 h-6"><path d="M1.5 8.67v8.58a3 3 0 003 3h15a3 3 0 003-3V8.67l-8.928 5.493a3 3 0 01-3.144 0L1.5 8.67z" /><path d="M22.5 6.908V6.75a3 3 0 00-3-3h-15a3 3 0 00-3 3v.158l9.714 5.978a1.5 1.5 0 001.572 0L22.5 6.908z" /></svg>';	echo '<span class="screen-reader-text">' . esc_html__( 'Share via Email', 'aqualuxe' ) . '</span>';	echo '</a>';		echo '</div>';	echo '</div>';}add_action( 'woocommerce_share', 'aqualuxe_product_sharing' );/** * Add wishlist button to single product. */function aqualuxe_single_product_wishlist_button() {	if ( ! get_theme_mod( 'aqualuxe_show_wishlist', true ) ) {		return;	}		global $product;		echo '<button class="wishlist-button single-product-wishlist" data-product-id="' . esc_attr( $product->get_id() ) . '">';	echo '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" class="w-6 h-6"><path d="M11.645 20.91l-.007-.003-.022-.012a15.247 15.247 0 01-.383-.218 25.18 25.18 0 01-4.244-3.17C4.688 15.36 2.25 12.174 2.25 8.25 2.25 5.322 4.714 3 7.688 3A5.5 5.5 0 0112 5.052 5.5 5.5 0 0116.313 3c2.973 0 5.437 2.322 5.437 5.25 0 3.925-2.438 7.111-4.739 9.256a25.175 25.175 0 01-4.244 3.17 15.247 15.247 0 01-.383.219l-.022.012-.007.004-.003.001a.752.752 0 01-.704 0l-.003-.001z" /></svg>';	echo '<span>' . esc_html__( 'Add to Wishlist', 'aqualuxe' ) . '</span>';	echo '</button>';}add_action( 'woocommerce_after_add_to_cart_button', 'aqualuxe_single_product_wishlist_button', 10 );/** * Add compare button to single product. */function aqualuxe_single_product_compare_button() {	global $product;		echo '<button class="compare-button single-product-compare" data-product-id="' . esc_attr( $product->get_id() ) . '">';	echo '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" class="w-6 h-6"><path d="M18.375 2.25c-1.035 0-1.875.84-1.875 1.875v15.75c0 1.035.84 1.875 1.875 1.875h.75c1.035 0 1.875-.84 1.875-1.875V4.125c0-1.036-.84-1.875-1.875-1.875h-.75zM9.75 8.625c0-1.036.84-1.875 1.875-1.875h.75c1.036 0 1.875.84 1.875 1.875v11.25c0 1.035-.84 1.875-1.875 1.875h-.75a1.875 1.875 0 01-1.875-1.875V8.625zM3 13.125c0-1.036.84-1.875 1.875-1.875h.75c1.036 0 1.875.84 1.875 1.875v6.75c0 1.035-.84 1.875-1.875 1.875h-.75A1.875 1.875 0 013 19.875v-6.75z" /></svg>';	echo '<span>' . esc_html__( 'Compare', 'aqualuxe' ) . '</span>';	echo '</button>';}add_action( 'woocommerce_after_add_to_cart_button', 'aqualuxe_single_product_compare_button', 20 );/** * Add recently viewed products to single product. */function aqualuxe_recently_viewed_products() {	if ( ! is_singular( 'product' ) ) {		return;	}		echo '<div class="recently-viewed-products">';	echo '<h2 class="recently-viewed-title">' . esc_html__( 'Recently Viewed Products', 'aqualuxe' ) . '</h2>';	echo do_shortcode( '[recently_viewed_products limit="4" columns="4"]' );	echo '</div>';}add_action( 'woocommerce_after_single_product', 'aqualuxe_recently_viewed_products', 20 );